# IaC: Terraform HCL to provision an AWS EC2 instance + S3 bucket
# A single apply command creates all resources in parallel

provider "aws" {
  region = "us-west-2"
}

resource "aws_instance" "sap_app_server" {
  ami           = "ami-0c55b159cbfafe1f0"
  instance_type = "r5.2xlarge"
  subnet_id     = aws_subnet.sap_subnet.id

  tags = {
    Name        = "sap-app-prd-001"
    Environment = "production"
    ManagedBy   = "terraform"
  }

  root_block_device {
    volume_size = 100
    volume_type = "gp3"
  }
}

resource "aws_s3_bucket" "sap_backup" {
  bucket = "sap-prd-backups-us-west-2"

  versioning {
    enabled = true
  }

  lifecycle_rule {
    id      = "archive"
    enabled = true
    transition {
      days          = 90
      storage_class = "GLACIER"
    }
  }
}

output "instance_ip" {
  value = aws_instance.sap_app_server.public_ip
}

# Compare to SAP Transport:
# Transport Request: ZDEVK900001 (contains ABAP code objects)
# Imported manually via STMS or automatically via CI pipeline
# Only handles ABAP objects, takes hours to days to promote
# Cannot create cloud resources, configure networks, or manage storage
#
# The mental shift: IaC treats infrastructure like code
# SAP transport treats code like infrastructure (move it between systems)
